  useEffect(() => {
    if (!processInfo || !inTauri) return;

    const setupListeners = async () => {
      const { listen } = await import('@tauri-apps/api/event');

      const unlistenOutput = await listen<PtyOutput>('pty-output', (event) => {
        if (event.payload.id === processInfo.id) {
          setOutput((prev) => [...prev, event.payload.data]);
        }
      });

      const unlistenExit = await listen<PtyExit>('pty-exit', (event) => {
        if (event.payload.id === processInfo.id) {
          setStatus('stopped');
          setOutput((prev) => [
            ...prev,
            `\n\x1b[33m[Process exited with code: ${event.payload.code ?? 'unknown'}]\x1b[0m\n`,
          ]);
        }
      });

      unlistenRef.current = [unlistenOutput, unlistenExit];
    };

    setupListeners();

    return () => {
      unlistenRef.current.forEach((unlisten) => unlisten());
      unlistenRef.current = [];
    };
  }, [processInfo, inTauri]);

